CREATE TABLE IF NOT EXISTS money_savings_goals (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES auth.users NOT NULL, name TEXT NOT NULL, target_amount DECIMAL(10,2) NOT NULL, saved_amount DECIMAL(10,2) DEFAULT 0, deadline DATE, icon TEXT DEFAULT '??', color TEXT DEFAULT '#00FFFF', created_at TIMESTAMPTZ DEFAULT NOW()); ALTER TABLE money_savings_goals ENABLE ROW LEVEL SECURITY; CREATE POLICY \" "own\ ON money_savings_goals FOR ALL TO authenticated USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id); 
